from langchain_openai import ChatOpenAI
from langchain_core.tools import tool
from langchain_core.messages import HumanMessage
from langgraph.prebuilt import create_react_agent

@tool
def get_weather(city: str) -> str:
    """Get the current weather for a city."""
    weather_data = {"tokyo": "80F, Sunny", "london": "58F, Rainy"}
    return weather_data.get(city.lower(), f"No data for {city}")

@tool
def add_numbers(a: int, b: int) -> str:
    """Add two numbers together."""
    return f"Result: {a + b}"

tools = [get_weather, add_numbers]
agent = create_react_agent(
    model="openai:gpt-4o-mini",
    tools=tools,
    prompt="You are a helpful assistant. Be concise."
)

result = agent.invoke(
    {"messages": [HumanMessage(content="What's the weather in Tokyo?")]}
)
print(result["messages"][-1].content)

from crewai import Agent, Crew, Process, Task
from crewai.project import CrewBase, agent, crew, task

@CrewBase
class GameBuilderCrew:
    agents_config = 'config/agents.yaml'
    tasks_config = 'config/tasks.yaml'

    @agent
    def senior_engineer_agent(self) -> Agent:
        config = self.agents_config['senior_engineer_agent']
        config['backstory'] += f"\n\nGame Design Requirements:\n{self.game_design}"
        return Agent(config=config, allow_delegation=False, verbose=True)

    @agent
    def qa_engineer_agent(self) -> Agent:
        return Agent(config=self.agents_config['qa_engineer_agent'],
                      allow_delegation=False, verbose=True)

    @task
    def write_code_task(self) -> Task:
        return Task(config=self.tasks_config['write_code_task'],
                    agent=self.senior_engineer_agent())

    @task
    def review_code_task(self) -> Task:
        return Task(config=self.tasks_config['review_code_task'],
                    agent=self.qa_engineer_agent())

    @crew
    def crew(self) -> Crew:
        return Crew(
            agents=self.agents,
            tasks=self.tasks,
            process=Process.sequential,
            verbose=True
        )
